import os
import numpy as np
from typing import List, Dict, Any
import json
import pickle
from pathlib import Path

class SimpleVectorDB:
    def __init__(self, dimension: int = 384):
        self.dimension = dimension
        self.vectors = []
        self.metadata = []
        self.documents = []
        
    def add_documents(self, texts: List[str], embeddings: np.ndarray, metadata: List[Dict] = None):
        if metadata is None:
            metadata = [{"id": i} for i in range(len(texts))]
        
        self.vectors.extend(embeddings)
        self.documents.extend(texts)
        self.metadata.extend(metadata)
    
    def search(self, query_embedding: np.ndarray, top_k: int = 5) -> List[Dict[str, Any]]:
        if len(self.vectors) == 0:
            return []
        
        vectors_array = np.array(self.vectors)
        similarities = np.dot(vectors_array, query_embedding) / (
            np.linalg.norm(vectors_array, axis=1) * np.linalg.norm(query_embedding)
        )
        
        top_indices = np.argsort(similarities)[::-1][:top_k]
        
        results = []
        for idx in top_indices:
            results.append({
                "text": self.documents[idx],
                "metadata": self.metadata[idx],
                "score": float(similarities[idx])
            })
        
        return results
    
    def save(self, path: str):
        data = {
            "vectors": self.vectors,
            "documents": self.documents,
            "metadata": self.metadata,
            "dimension": self.dimension
        }
        with open(path, 'wb') as f:
            pickle.dump(data, f)
    
    def load(self, path: str):
        with open(path, 'rb') as f:
            data = pickle.load(f)
        self.vectors = data["vectors"]
        self.documents = data["documents"]
        self.metadata = data["metadata"]
        self.dimension = data["dimension"]


class SimpleEmbedding:
    def __init__(self):
        try:
            from sentence_transformers import SentenceTransformer
            self.model = SentenceTransformer('all-MiniLM-L6-v2')
            self.use_sentence_transformers = True
        except ImportError:
            self.use_sentence_transformers = False
            print("sentence-transformers not installed, using simple TF-IDF embeddings")
            self.vocabulary = {}
            self.idf = {}
    
    def _build_vocabulary(self, texts: List[str]):
        from collections import Counter
        word_doc_count = Counter()
        all_words = set()
        
        for text in texts:
            words = set(text.lower().split())
            all_words.update(words)
            for word in words:
                word_doc_count[word] += 1
        
        self.vocabulary = {word: idx for idx, word in enumerate(sorted(all_words))}
        
        num_docs = len(texts)
        self.idf = {
            word: np.log(num_docs / (count + 1))
            for word, count in word_doc_count.items()
        }
    
    def _tfidf_embed(self, text: str) -> np.ndarray:
        from collections import Counter
        words = text.lower().split()
        word_count = Counter(words)
        
        vector = np.zeros(len(self.vocabulary))
        
        total_words = len(words)
        if total_words == 0:
            return vector
        
        for word, count in word_count.items():
            if word in self.vocabulary:
                tf = count / total_words
                idf = self.idf.get(word, 0)
                vector[self.vocabulary[word]] = tf * idf
        
        norm = np.linalg.norm(vector)
        if norm > 0:
            vector = vector / norm
        
        return vector
    
    def embed_documents(self, texts: List[str]) -> np.ndarray:
        if self.use_sentence_transformers:
            return self.model.encode(texts, convert_to_numpy=True)
        else:
            if not self.vocabulary:
                self._build_vocabulary(texts)
            return np.array([self._tfidf_embed(text) for text in texts])
    
    def embed_query(self, text: str) -> np.ndarray:
        if self.use_sentence_transformers:
            return self.model.encode([text], convert_to_numpy=True)[0]
        else:
            return self._tfidf_embed(text)


class DocumentLoader:
    @staticmethod
    def load_text_file(file_path: str) -> str:
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()
    
    @staticmethod
    def load_directory(directory: str, extensions: List[str] = None) -> List[Dict[str, str]]:
        if extensions is None:
            extensions = ['.txt', '.md', '.json', '.csv']
        
        documents = []
        directory_path = Path(directory)
        
        for file_path in directory_path.rglob('*'):
            if file_path.is_file() and file_path.suffix in extensions:
                try:
                    content = DocumentLoader.load_text_file(str(file_path))
                    documents.append({
                        "content": content,
                        "source": str(file_path),
                        "filename": file_path.name
                    })
                except Exception as e:
                    print(f"Error loading {file_path}: {e}")
        
        return documents


class TextSplitter:
    def __init__(self, chunk_size: int = 500, chunk_overlap: int = 50):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap
    
    def split_text(self, text: str) -> List[str]:
        chunks = []
        start = 0
        text_length = len(text)
        
        while start < text_length:
            end = start + self.chunk_size
            chunk = text[start:end]
            
            if end < text_length:
                last_space = chunk.rfind(' ')
                if last_space != -1 and last_space > self.chunk_size // 2:
                    end = start + last_space
                    chunk = text[start:end]
            
            if chunk.strip():
                chunks.append(chunk.strip())
            
            start = end - self.chunk_overlap
            if start >= text_length:
                break
        
        return chunks
    
    def split_documents(self, documents: List[Dict[str, str]]) -> List[Dict[str, Any]]:
        split_docs = []
        
        for doc in documents:
            chunks = self.split_text(doc["content"])
            for i, chunk in enumerate(chunks):
                split_docs.append({
                    "content": chunk,
                    "source": doc.get("source", "unknown"),
                    "filename": doc.get("filename", "unknown"),
                    "chunk_id": i
                })
        
        return split_docs


class LLMClient:
    def __init__(self, api_key: str = None, model: str = "gpt-3.5-turbo"):
        self.api_key = api_key or os.getenv("OPENAI_API_KEY")
        self.model = model
        self.use_openai = False
        
        if self.api_key:
            try:
                import openai
                self.client = openai.OpenAI(api_key=self.api_key)
                self.use_openai = True
            except ImportError:
                print("openai package not installed")
    
    def generate(self, prompt: str, max_tokens: int = 1000) -> str:
        if self.use_openai:
            try:
                response = self.client.chat.completions.create(
                    model=self.model,
                    messages=[{"role": "user", "content": prompt}],
                    max_tokens=max_tokens,
                    temperature=0.7
                )
                return response.choices[0].message.content
            except Exception as e:
                return f"Error generating response: {e}"
        else:
            return "LLM not configured. Please provide an OpenAI API key or implement a custom LLM client."


class RAGSystem:
    def __init__(self, db_path: str = "vector_db.pkl", embedding_model: str = "all-MiniLM-L6-v2"):
        self.db_path = db_path
        self.vector_db = SimpleVectorDB()
        self.embedder = SimpleEmbedding()
        self.text_splitter = TextSplitter(chunk_size=500, chunk_overlap=50)
        self.llm = LLMClient()
        
        if os.path.exists(db_path):
            self.vector_db.load(db_path)
            print(f"Loaded existing vector database from {db_path}")
    
    def load_documents(self, directory: str, extensions: List[str] = None):
        print(f"Loading documents from {directory}...")
        documents = DocumentLoader.load_directory(directory, extensions)
        print(f"Loaded {len(documents)} documents")
        
        print("Splitting documents into chunks...")
        split_docs = self.text_splitter.split_documents(documents)
        print(f"Created {len(split_docs)} chunks")
        
        print("Generating embeddings...")
        texts = [doc["content"] for doc in split_docs]
        embeddings = self.embedder.embed_documents(texts)
        
        metadata = [{
            "source": doc["source"],
            "filename": doc["filename"],
            "chunk_id": doc["chunk_id"]
        } for doc in split_docs]
        
        self.vector_db.add_documents(texts, embeddings, metadata)
        print(f"Added {len(texts)} chunks to vector database")
        
        self.save_database()
    
    def save_database(self):
        self.vector_db.save(self.db_path)
        print(f"Saved vector database to {self.db_path}")
    
    def query(self, query_text: str, top_k: int = 5) -> Dict[str, Any]:
        print(f"Processing query: {query_text}")
        
        query_embedding = self.embedder.embed_query(query_text)
        
        results = self.vector_db.search(query_embedding, top_k=top_k)
        
        context = self._build_context(results)
        
        prompt = self._build_prompt(query_text, results)
        
        response = self.llm.generate(prompt)
        
        return {
            "query": query_text,
            "response": response,
            "retrieved_documents": results,
            "context": context
        }
    
    def _build_context(self, results: List[Dict[str, Any]]) -> str:
        context_parts = []
        for i, result in enumerate(results, 1):
            source = result["metadata"].get("filename", "unknown")
            text = result["text"]
            context_parts.append(f"[Document {i} - {source}]\n{text}\n")
        
        return "\n".join(context_parts)
    
    def _build_prompt(self, query: str, results: List[Dict[str, Any]]) -> str:
        context = self._build_context(results)
        
        prompt = f"""You are a helpful assistant that answers questions based on the provided company documents.

Context from company knowledge base:
{context}

Question: {query}

Instructions:
- Answer the question based on the context provided above
- If the context doesn't contain enough information to answer the question, say so
- Be concise and accurate
- Cite which document(s) your answer comes from when relevant

Answer:"""
        
        return prompt
    
    def interactive_mode(self):
        print("\n=== RAG System Interactive Mode ===")
        print("Type 'quit' or 'exit' to stop\n")
        
        while True:
            query = input("Enter your question: ").strip()
            
            if query.lower() in ['quit', 'exit', 'q']:
                print("Exiting...")
                break
            
            if not query:
                continue
            
            result = self.query(query)
            
            print("\n--- Response ---")
            print(result["response"])
            print("\n--- Retrieved Documents ---")
            for i, doc in enumerate(result["retrieved_documents"], 1):
                print(f"{i}. {doc['metadata']['filename']} (score: {doc['score']:.3f})")
            print("\n" + "="*50 + "\n")


